// 三载体一致:纯 JS,无 DOM/uplink/shadow 足迹
import { PCA } from 'https://cdn.jsdelivr.net/npm/ml-pca@4/+esm';          // 命名导出,无 default
const pca = new PCA(data.dataset, { method: data.method ?? 'SVD', center: data.center ?? true, scale: data.scale ?? false });
const scores = pca.predict(data.dataset).to2DArray();  // predict 返回 ml-matrix Matrix,须 .to2DArray()
const explained = pca.getExplainedVariance();          // 各主成分解释方差比 number[]
const cumulative = pca.getCumulativeVariance();
// 2D 散点:scores 每行取前两列作 (x,y);用 explained[0]/explained[1] 标注两轴解释力
